solution_code:
#include <iostream>

struct Vec2 {
    int x{};
    int y{};
};

Vec2 operator+(const Vec2& lhs, const Vec2& rhs) {
    return Vec2{lhs.x + rhs.x, lhs.y + rhs.y};
}

int main() {
    Vec2 a, b;
    std::cin >> a.x >> a.y;
    std::cin >> b.x >> b.y;

    Vec2 result = a + b;
    std::cout << "Result: " << result.x << " " << result.y << "\n";
    return 0;
}

